import{_ as s,o as e,c as i,a5 as n}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：单相 PFC 平均控制链","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 平均控制链","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）的平均模型（averaged model）把“开关每个周期怎么翻转”暂时压缩掉，只保留控制链路中的慢变量："},"headers":[],"relativePath":"content/power/concepts/single-phase-pfc-average-controller.md","filePath":"content/power/concepts/single-phase-pfc-average-controller.md","lastUpdated":1782835746000}'),l={name:"content/power/concepts/single-phase-pfc-average-controller.md"};function t(p,a,o,c,r,d){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="概念-单相-pfc-平均控制链" tabindex="-1">概念：单相 PFC 平均控制链 <a class="header-anchor" href="#概念-单相-pfc-平均控制链" aria-label="Permalink to &quot;概念：单相 PFC 平均控制链&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）的平均模型（averaged model）把“开关每个周期怎么翻转”暂时压缩掉，只保留控制链路中的慢变量：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>母线电压误差 -&gt; 电压环 -&gt; 电导命令/功率命令 -&gt; 前馈 -&gt; 电流参考 -&gt; 电流环/PWM -&gt; 输入功率 -&gt; 母线电压</span></span></code></pre></div><p>本节只讲一个概念：把前面几节学过的电压环（voltage loop）、前馈（feedforward）、电流环（current loop）、脉宽调制（pulse-width modulation / PWM）延迟串成一条能看懂的 PFC 控制链。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）工程代码通常不是按课程顺序分开的。你读到的可能是一个控制中断服务程序（control interrupt service routine / control ISR），里面同时出现采样、RMS 估算、电压环、电流参考、限幅、PWM 更新和保护判断。</p><p>平均控制链的作用是先建立“信号从哪里来、到哪里去”的地图。没有这张地图，读完整 C 工程时容易只看到局部公式，看不出它服务于哪一段能量流。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>负载突然变大时，直流母线电容先放电，母线电压下降。电压环看到误差后提高电导命令，PFC 从输入侧吸取更多功率。电流环和 PWM 不是无限快，所以实际输入功率会滞后命令功率一小段时间。输入功率大于负载功率后，母线电压逐步回到参考值。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>教学平均模型使用下面几条关系：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e_v = Vbus_ref - Vbus</span></span>
<span class="line"><span>G_cmd = clamp(Kp * e_v + integral(Ki * e_v), Gmin, Gmax)</span></span>
<span class="line"><span>Irms_ref = G_cmd * Vrms</span></span>
<span class="line"><span>Pin_cmd = G_cmd * Vrms^2</span></span>
<span class="line"><span>Pin_actual[k] = low_pass(delay(Pin_cmd), current_loop_bandwidth)</span></span>
<span class="line"><span>Cbus * d(Vbus^2) / 2 = (Pin_actual - Pload) * dt</span></span></code></pre></div><p>这里 <code>Pin_actual</code> 不是开关级瞬时功率，而是被电流环带宽和延迟限制后的平均输入功率。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_average_controller.py</span></span></code></pre></div><p>观察：</p><ul><li>负载从 700 W 跳到 1200 W 后，母线电压先下跌。</li><li>电压环提高 <code>G_cmd</code>，<code>Irms_ref</code> 和 <code>Pin_cmd</code> 随之升高。</li><li><code>Pin_actual</code> 因电流环带宽和延迟滞后于 <code>Pin_cmd</code>。</li><li>母线电压在输入功率追上后回到参考附近。</li></ul><p>延迟对比：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_average_controller.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">delay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">samples </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_average_delay_0.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_average_controller.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">delay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">samples </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_average_delay_5.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>读固件时可以按这条链路找变量：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC samples</span></span>
<span class="line"><span>  -&gt; Vbus, Vin, Iin scaling/filtering</span></span>
<span class="line"><span>  -&gt; Vrms estimation</span></span>
<span class="line"><span>  -&gt; voltage loop output</span></span>
<span class="line"><span>  -&gt; feedforward and limit</span></span>
<span class="line"><span>  -&gt; current reference</span></span>
<span class="line"><span>  -&gt; current loop</span></span>
<span class="line"><span>  -&gt; PWM compare update</span></span></code></pre></div><p>工程代码里还会叠加保护逻辑、模式状态机、软启动、限流、故障锁存和通信参数。本节模型不包含这些内容，但它能帮助你识别主控制链。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：平均模型能替代开关仿真。<br> 正确理解：平均模型适合看控制链和慢动态，不能看开关纹波、二极管反向恢复、采样尖峰。</p></li><li><p>错误理解：电压环输出就是占空比。<br> 正确理解：PFC 里电压环通常输出功率、电导或电流幅值类命令，内层电流环才产生 PWM 相关命令。</p></li><li><p>错误理解：母线电压下跌说明电压环一定错了。<br> 正确理解：负载突变时电容先承担能量差，短暂下跌是正常动态，要看是否能恢复、是否超限。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能按顺序说出 <code>Vbus error -&gt; G_cmd -&gt; Irms_ref -&gt; Pin_actual -&gt; Vbus</code> 的因果链。</li><li>能解释负载阶跃后为什么母线电压先跌再恢复。</li><li>能在图中指出 <code>Vbus</code>、<code>Pload</code>、<code>Pin_cmd</code>、<code>Pin_actual</code>、<code>G_cmd</code>、<code>Irms_ref</code> 和 <code>D_proxy</code>。</li><li>能解释 <code>--delay-samples</code> 增大时，为什么 <code>Pin_actual</code> 更滞后于 <code>Pin_cmd</code>。</li><li>能基于生成的仿真图准备导师问题，而不是只问抽象概念。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>负载从 700 W 跳到 1200 W 后，母线电压为什么不会立刻保持在 380 V？</li><li><code>Pin_cmd</code> 和 <code>Pin_actual</code> 的差值主要代表哪两类工程因素？</li><li>如果 <code>G_cmd</code> 达到上限，母线仍然下跌，你会优先怀疑控制参数、功率能力还是保护限流？为什么？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_average_controller.py</code> 看到负载阶跃后，<code>Pin_cmd</code> 先上升，<code>Pin_actual</code> 因延迟滞后。公司 PFC 控制中电压环输出通常是功率命令、电导命令还是电流幅值命令？</li><li>图中 <code>delay_samples=2</code> 会增加输入功率跟踪误差。实际平台从 ADC 采样到 PWM 生效的延迟一般怎样计算？</li><li>如果真实产品还叠加限流和软启动，公司代码里这些限制通常放在电压环输出之后，还是电流参考生成之后？</li></ul>`,34)])])}const g=s(l,[["render",t]]);export{u as __pageData,g as default};
